const ON_SENTINEL_VISIBLE = 'OnSentinelVisible';

class ScrollObserver {
    #dotNetRef;
    #observer;

    constructor(dotNetRef, sentinel) {
        this.#dotNetRef = dotNetRef;
        this.#observer = new IntersectionObserver(async (entries) => {
            if (entries[0].isIntersecting) {
                try {
                    await this.#dotNetRef.invokeMethodAsync(ON_SENTINEL_VISIBLE);
                } catch { /* circuit disconnected */ }
            }
        }, { rootMargin: '128px' });
        this.#observer.observe(sentinel);
    }

    dispose() {
        this.#observer.disconnect();
    }
}

let instance;

export function initialize(dotNetRef, sentinel) {
    instance = new ScrollObserver(dotNetRef, sentinel);
}

export function dispose() {
    instance?.dispose();
    instance = null;
}

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_597864fd7d694e109b6eceb5abe6fda5.Components;

public sealed class InfiniteScrollListInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/InfiniteScrollList.razor.js";
    internal const string InitMethod = "initialize";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public InfiniteScrollListInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync(
        DotNetObjectReference<object> dotNetRef, ElementReference sentinel)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, dotNetRef, sentinel);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

@typeparam TItem
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private InfiniteScrollListInterop? _interop;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private bool _hasMoreChanged;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override void OnParametersSet()
    {
        _hasMoreChanged = true;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            await InitializeObserverAsync();
        }
        else if (_hasMoreChanged && !firstRender)
        {
            _hasMoreChanged = false;

            if (HasMore && _interop is null)
            {
                await InitializeObserverAsync();
            }
            else if (!HasMore && _interop is not null)
            {
                await DisposeInteropAsync();
            }
        }
    }

    private async Task InitializeObserverAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        _interop = new InfiniteScrollListInterop(JS);
        await _interop.InitializeAsync(
            DotNetObjectReference.Create<object>(this), _sentinelRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        await InvokeAsync(async () =>
        {
            _isLoading = true;
            StateHasChanged();

            await OnLoadMore.InvokeAsync();

            _isLoading = false;
            StateHasChanged();
        });
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeInteropAsync();
        _dotNetRef?.Dispose();
    }

    private async ValueTask DisposeInteropAsync()
    {
        if (_interop is not null)
        {
            await _interop.DisposeAsync();
            _interop = null;
        }
    }
}

