class ScrollObserver {
    #dotNetRef;
    #observer;

    constructor(dotNetRef, sentinel) {
        this.#dotNetRef = dotNetRef;
        this.#observer = new IntersectionObserver(async (entries) => {
            if (entries[0].isIntersecting) {
                try {
                    await this.#dotNetRef.invokeMethodAsync(ON_SENTINEL_VISIBLE);
                } catch { /* circuit disconnected */ }
            }
        }, { rootMargin: '128px' });
        this.#observer.observe(sentinel);
    }

    dispose() {
        this.#observer.disconnect();
    }
}

let instance;

export function initialize(dotNetRef, sentinel) {
    instance = new ScrollObserver(dotNetRef, sentinel);
}

export function dispose() {
    instance?.dispose();
    instance = null;
}

